export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const survivors = liveCells.filter(
    (cell) => countLiveNeighbors(cell, liveCells) === 3,
  );
  const births: Cell[] = [];
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx += 1) {
      for (let dy = -1; dy <= 1; dy += 1) {
        const candidate: Cell = [x + dx, y + dy];
        if (
          !containsCell(liveCells, candidate) &&
          !containsCell(births, candidate) &&
          countLiveNeighbors(candidate, liveCells) === 3
        ) {
          births.push(candidate);
        }
      }
    }
  }
  return [...survivors, ...births];
